export function AttendanceHeader() {
  return (
    <div>
      <h1
        style={{
          fontFamily: "DM Sans, sans-serif",
          fontSize: "24px",
          fontWeight: "600",
          color: "#0A0A0A",
        }}
      >
        Attendance
      </h1>
    </div>
  );
}

import { Clock } from "lucide-react";

export function AttendanceHeader() {
  return (
    <div className="mb-6">
      <div className="flex items-center gap-3 mb-2">
        <div
          className="p-2 rounded-lg"
          style={{
            backgroundColor: "rgba(22, 119, 255, 0.1)",
            color: "#1677ff",
          }}
        >
          <Clock className="w-6 h-6" />
        </div>
        <h1
          style={{
            fontFamily: "DM Sans, sans-serif",
            fontSize: "28px",
            fontWeight: "700",
            color: "#0A0A0A",
            margin: 0,
          }}
        >
          Attendance
        </h1>
      </div>
      <p
        style={{
          fontSize: "14px",
          color: "#595959",
          margin: 0,
          paddingLeft: "44px",
        }}
      >
        Track your daily attendance and work hours
      </p>
    </div>
  );
}

import { Alert, Button, Form, Input, InputNumber, Modal, Select, Table, Tag } from "antd";
import { Clock, Plus, CheckCircle, FileText } from "lucide-react";

function renderOvertimeStatusTag(status) {
  if (status === "APPROVED") return <Tag color="success">Approved</Tag>;
  if (status === "REJECTED") return <Tag color="error">Rejected</Tag>;
  if (status === "CANCELLED") return <Tag color="default">Cancelled</Tag>;
  if (status === "PENDING_DEPARTMENT") return <Tag color="warning">Pending (Dept)</Tag>;
  if (status === "PENDING_OFFICE") return <Tag color="warning">Pending (Office)</Tag>;
  return <Tag color="warning">Pending</Tag>;
}

export function OvertimeSection({
  canCreateOvertime,
  canManageOvertimeApprovals,
  isDepartmentManager,
  isOfficeManager,
  loading,
  todayOvertimeSession,
  isOvertimeSessionCheckedIn,
  isOvertimeSessionCheckedOut,
  hasApprovedOvertimeRequestForToday,
  hasTodayAttendanceLog,
  myOvertimeRequests,
  myOvertimeReports,
  approvalScopeOvertimeRequests,
  approvalQueueOvertimeReports,
  myOvertimeRequestStatusFilter,
  setMyOvertimeRequestStatusFilter,
  myOvertimeReportStatusFilter,
  setMyOvertimeReportStatusFilter,
  pendingOvertimeRequestStatusFilter,
  setPendingOvertimeRequestStatusFilter,
  pendingOvertimeReportStatusFilter,
  setPendingOvertimeReportStatusFilter,
  isSubmittingOvertimeAction,
  overtimeRequestForm,
  overtimeReportForm,
  onRequestNew,
  onReportNew,
  onCheckIn,
  onCheckOut,
  onCreateRequest,
  onCreateReport,
  onApproveRequest,
  onRejectRequest,
  onApproveReport,
  onRejectReport,
}) {
  const filteredMyOvertimeRequests = myOvertimeRequests.filter((r) =>
    myOvertimeRequestStatusFilter === "ALL" ? true : r.status === myOvertimeRequestStatusFilter
  );

  const filteredMyOvertimeReports = myOvertimeReports.filter((r) =>
    myOvertimeReportStatusFilter === "ALL" ? true : r.status === myOvertimeReportStatusFilter
  );

  const filteredApprovalScopeOvertimeRequests = approvalScopeOvertimeRequests.filter((r) =>
    pendingOvertimeRequestStatusFilter === "ALL" ? true : r.status === pendingOvertimeRequestStatusFilter
  );

  const filteredApprovalQueueOvertimeReports = approvalQueueOvertimeReports.filter((r) =>
    pendingOvertimeReportStatusFilter === "ALL" ? true : r.status === pendingOvertimeReportStatusFilter
  );

  return (
    <div className="space-y-6">
      {/* OT Workflow Section */}
      <div className="section-card">
        <div
          className="section-header section-ot-header"
          style={{ borderColor: "rgba(250, 140, 22, 0.2)" }}
        >
          <div className="section-header-icon" style={{ color: "#fa8c16" }}>
            <Clock className="w-5 h-5" />
          </div>
          <h3 style={{ margin: 0, flex: 1 }}>Overtime Workflow</h3>
          {canCreateOvertime && (
            <Button type="primary" size="small" icon={<Plus className="w-4 h-4" />} onClick={onRequestNew} style={{ marginTop: "-4px" }}>
              New Request
            </Button>
          )}
        </div>

        <div className="section-content space-y-4">
          {!hasTodayAttendanceLog && (
            <Alert type="warning" showIcon message="Please check in attendance for today before submitting OT report." />
          )}

          {/* OT Session Controls */}
          <div className="flex items-center gap-3 p-4 rounded-lg" style={{ backgroundColor: "rgba(250, 140, 22, 0.05)", border: "1px solid rgba(250, 140, 22, 0.2)" }}>
            <div style={{ flex: 1 }}>
              <span style={{ fontSize: "14px", fontWeight: "600", color: "#0a0a0a" }}>
                {isOvertimeSessionCheckedOut ? "✓ OT session completed" : isOvertimeSessionCheckedIn ? "◆ OT session checked in" : "OT session: Not started"}
              </span>
            </div>
            <div className="flex gap-2">
              <Button
                onClick={onCheckIn}
                disabled={!hasApprovedOvertimeRequestForToday || isOvertimeSessionCheckedIn || isOvertimeSessionCheckedOut}
                loading={isSubmittingOvertimeAction && !isOvertimeSessionCheckedIn}
                icon={<CheckCircle className="w-4 h-4" />}
              >
                OT Check-in
              </Button>
              <Button
                onClick={onCheckOut}
                disabled={!isOvertimeSessionCheckedIn}
                loading={isSubmittingOvertimeAction && isOvertimeSessionCheckedIn}
              >
                OT Check-out
              </Button>
              {canCreateOvertime && (
                <Button
                  type="primary"
                  onClick={onReportNew}
                  disabled={!hasApprovedOvertimeRequestForToday || !isOvertimeSessionCheckedOut || !hasTodayAttendanceLog}
                  icon={<FileText className="w-4 h-4" />}
                >
                  Submit Report
                </Button>
              )}
            </div>
          </div>

          {/* My OT Requests */}
          {canCreateOvertime && (
            <div>
              <h4 style={{ fontSize: "13px", fontWeight: "700", color: "#0a0a0a", marginBottom: "12px", textTransform: "uppercase" }}>
                My OT Requests
              </h4>
              <Select
                value={myOvertimeRequestStatusFilter}
                onChange={setMyOvertimeRequestStatusFilter}
                style={{ width: 180, marginBottom: 12 }}
                options={[
                  { value: "ALL", label: "All status" },
                  { value: "PENDING_DEPARTMENT", label: "Pending (Dept)" },
                  { value: "PENDING_OFFICE", label: "Pending (Office)" },
                  { value: "APPROVED", label: "Approved" },
                  { value: "REJECTED", label: "Rejected" },
                ]}
                size="small"
              />
              <Table
                rowKey={(r) => r.id}
                loading={loading}
                dataSource={filteredMyOvertimeRequests}
                size="small"
                pagination={{ pageSize: 5 }}
                columns={[
                  { title: "Date", dataIndex: "logDate", key: "logDate", width: 100 },
                  { title: "Reason", dataIndex: "reason", key: "reason", ellipsis: true },
                  { title: "Status", key: "status", width: 120, render: (_, r) => renderOvertimeStatusTag(r.status) },
                ]}
                locale={{ emptyText: "No OT requests yet." }}
              />
            </div>
          )}

          {/* My OT Reports */}
          {canCreateOvertime && (
            <div>
              <h4 style={{ fontSize: "13px", fontWeight: "700", color: "#0a0a0a", marginBottom: "12px", textTransform: "uppercase" }}>
                My OT Reports
              </h4>
              <Select
                value={myOvertimeReportStatusFilter}
                onChange={setMyOvertimeReportStatusFilter}
                style={{ width: 180, marginBottom: 12 }}
                options={[
                  { value: "ALL", label: "All status" },
                  { value: "PENDING_DEPARTMENT", label: "Pending (Dept)" },
                  { value: "PENDING_OFFICE", label: "Pending (Office)" },
                  { value: "APPROVED", label: "Approved" },
                  { value: "REJECTED", label: "Rejected" },
                ]}
                size="small"
              />
              <Table
                rowKey={(r) => r.id}
                loading={loading}
                dataSource={filteredMyOvertimeReports}
                size="small"
                pagination={{ pageSize: 5 }}
                columns={[
                  { title: "OT Hours", dataIndex: "reportedOtHours", key: "reportedOtHours", width: 100, render: (v) => `${v ?? 0}h` },
                  { title: "Note", dataIndex: "reportNote", key: "reportNote", ellipsis: true },
                  { title: "Status", key: "status", width: 120, render: (_, r) => renderOvertimeStatusTag(r.status) },
                ]}
                locale={{ emptyText: "No OT reports yet." }}
              />
            </div>
          )}

          {/* Approval Queues */}
          {canManageOvertimeApprovals && (
            <>
              <div style={{ borderTop: "1px solid #e8e8e8", paddingTop: "16px" }}>
                <h4 style={{ fontSize: "13px", fontWeight: "700", color: "#0a0a0a", marginBottom: "12px", textTransform: "uppercase" }}>
                  Pending OT Requests (Approval)
                </h4>
                <Select
                  value={pendingOvertimeRequestStatusFilter}
                  onChange={setPendingOvertimeRequestStatusFilter}
                  style={{ width: 180, marginBottom: 12 }}
                  options={[
                    { value: "ALL", label: "All status" },
                    { value: "PENDING_DEPARTMENT", label: "Pending (Dept)" },
                    { value: "PENDING_OFFICE", label: "Pending (Office)" },
                    { value: "APPROVED", label: "Approved" },
                    { value: "REJECTED", label: "Rejected" },
                  ]}
                  size="small"
                />
                <Table
                  rowKey={(r) => r.id}
                  loading={loading}
                  dataSource={filteredApprovalScopeOvertimeRequests}
                  size="small"
                  pagination={{ pageSize: 5 }}
                  columns={[
                    { title: "User", dataIndex: "userName", key: "userName" },
                    { title: "Date", dataIndex: "logDate", key: "logDate", width: 100 },
                    { title: "Reason", dataIndex: "reason", key: "reason", ellipsis: true },
                    { title: "Status", key: "status", width: 120, render: (_, r) => renderOvertimeStatusTag(r.status) },
                    {
                      title: "Action",
                      key: "action",
                      width: 150,
                      render: (_, r) => {
                        const canDecide =
                          (isDepartmentManager && (r.status === "PENDING_DEPARTMENT" || r.status === "PENDING")) ||
                          (isOfficeManager && r.status === "PENDING_OFFICE");
                        if (!canDecide) return <span style={{ color: "#8C8C8C" }}>—</span>;
                        return (
                          <div className="flex gap-2">
                            <Button size="small" type="primary" onClick={() => onApproveRequest(r.id)}>
                              Approve
                            </Button>
                            <Button size="small" danger onClick={() => onRejectRequest(r.id)}>
                              Reject
                            </Button>
                          </div>
                        );
                      },
                    },
                  ]}
                  locale={{ emptyText: "No pending OT requests." }}
                />
              </div>

              <div style={{ borderTop: "1px solid #e8e8e8", paddingTop: "16px" }}>
                <h4 style={{ fontSize: "13px", fontWeight: "700", color: "#0a0a0a", marginBottom: "12px", textTransform: "uppercase" }}>
                  Pending OT Reports (Approval)
                </h4>
                <Select
                  value={pendingOvertimeReportStatusFilter}
                  onChange={setPendingOvertimeReportStatusFilter}
                  style={{ width: 180, marginBottom: 12 }}
                  options={[
                    { value: "ALL", label: "All status" },
                    { value: "PENDING_DEPARTMENT", label: "Pending (Dept)" },
                    { value: "PENDING_OFFICE", label: "Pending (Office)" },
                    { value: "APPROVED", label: "Approved" },
                    { value: "REJECTED", label: "Rejected" },
                  ]}
                  size="small"
                />
                <Table
                  rowKey={(r) => r.id}
                  loading={loading}
                  dataSource={filteredApprovalQueueOvertimeReports}
                  size="small"
                  pagination={{ pageSize: 5 }}
                  columns={[
                    { title: "User", dataIndex: "userName", key: "userName" },
                    { title: "OT Hours", dataIndex: "reportedOtHours", key: "reportedOtHours", width: 100, render: (v) => `${v ?? 0}h` },
                    { title: "Note", dataIndex: "reportNote", key: "reportNote", ellipsis: true },
                    { title: "Status", key: "status", width: 120, render: (_, r) => renderOvertimeStatusTag(r.status) },
                    {
                      title: "Action",
                      key: "action",
                      width: 150,
                      render: (_, r) => {
                        const canDecide =
                          (isDepartmentManager && (r.status === "PENDING_DEPARTMENT" || r.status === "PENDING")) ||
                          (isOfficeManager && r.status === "PENDING_OFFICE");
                        if (!canDecide) return <span style={{ color: "#8C8C8C" }}>—</span>;
                        return (
                          <div className="flex gap-2">
                            <Button size="small" type="primary" onClick={() => onApproveReport(r.id)}>
                              Approve
                            </Button>
                            <Button size="small" danger onClick={() => onRejectReport(r.id)}>
                              Reject
                            </Button>
                          </div>
                        );
                      },
                    },
                  ]}
                  locale={{ emptyText: "No pending OT reports." }}
                />
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  );
}

import { Descriptions, Drawer, Tag } from "antd";

function n(value) {
  if (value == null) return "-";
  return `${Number(value).toLocaleString()} VND`;
}

function statusColor(status) {
  if (status === "PAID") return "success";
  if (status === "FINALIZED") return "processing";
  return "default";
}

export function PayrollDetailDrawer({ open, payroll, onClose }) {
  return (
    <Drawer title="Payroll Detail" open={open} onClose={onClose} width={640}>
      {!payroll ? null : (
        <Descriptions bordered column={1}>
          <Descriptions.Item label="User">{payroll.userName || "-"}</Descriptions.Item>
          <Descriptions.Item label="Period">{`${payroll.year}-${String(payroll.month).padStart(2, "0")}`}</Descriptions.Item>
          <Descriptions.Item label="Base Salary Snapshot">{n(payroll.baseSalarySnapshot)}</Descriptions.Item>
          <Descriptions.Item label="Working Days">{payroll.workingDaysInMonth ?? "-"}</Descriptions.Item>
          <Descriptions.Item label="Present Days">{payroll.presentDays ?? "-"}</Descriptions.Item>
          <Descriptions.Item label="Regular Hours">{payroll.regularHours != null ? `${payroll.regularHours}h` : "-"}</Descriptions.Item>
          <Descriptions.Item label="Regular Pay">{n(payroll.regularPay)}</Descriptions.Item>
          <Descriptions.Item label="Approved OT Hours">{payroll.otHours != null ? `${payroll.otHours}h` : "-"}</Descriptions.Item>
          <Descriptions.Item label="Approved OT Pay">{n(payroll.otPay)}</Descriptions.Item>
          <Descriptions.Item label="Net Salary">{n(payroll.netSalary)}</Descriptions.Item>
          <Descriptions.Item label="Status">{payroll.status ? <Tag color={statusColor(payroll.status)}>{payroll.status}</Tag> : "-"}</Descriptions.Item>
          <Descriptions.Item label="Generated At">{payroll.generatedAt ? String(payroll.generatedAt).replace("T", " ").slice(0, 19) : "-"}</Descriptions.Item>
        </Descriptions>
      )}
    </Drawer>
  );
}

import { Drawer, Tag, Row, Col, Divider } from "antd";
import { FileText } from "lucide-react";

function n(value) {
  if (value == null) return "-";
  return `${Number(value).toLocaleString()} VND`;
}

function statusColor(status) {
  if (status === "PAID") return "success";
  if (status === "FINALIZED") return "processing";
  return "default";
}

function DetailRow({ label, value, color = "text-primary", bold = false }) {
  return (
    <div style={{ marginBottom: "16px" }}>
      <div style={{ fontSize: "12px", fontWeight: "600", color: "#595959", textTransform: "uppercase", marginBottom: "6px" }}>
        {label}
      </div>
      <div
        style={{
          fontSize: "16px",
          fontWeight: bold ? "700" : "500",
          color: color === "success" ? "#52c41a" : color === "warning" ? "#fa8c16" : "#0a0a0a",
        }}
      >
        {value}
      </div>
    </div>
  );
}

export function PayrollDetailDrawer({ open, payroll, onClose }) {
  return (
    <Drawer
      title={
        <div style={{ display: "flex", alignItems: "center", gap: "8px" }}>
          <FileText style={{ color: "#52c41a" }} size={20} />
          <span>Payroll Details</span>
        </div>
      }
      open={open}
      onClose={onClose}
      width={720}
      bodyStyle={{ paddingBottom: 80 }}
    >
      {!payroll ? null : (
        <div>
          {/* Header Section */}
          <div style={{ marginBottom: "32px" }}>
            <DetailRow label="Employee Name" value={payroll.userName || "-"} bold />
            <div style={{ display: "flex", gap: "16px", marginTop: "16px" }}>
              <div style={{ flex: 1 }}>
                <DetailRow label="Period" value={`${payroll.year}-${String(payroll.month).padStart(2, "0")}`} />
              </div>
              <div style={{ flex: 1 }}>
                <DetailRow
                  label="Status"
                  value={payroll.status ? <Tag color={statusColor(payroll.status)}>{payroll.status}</Tag> : "-"}
                />
              </div>
            </div>
          </div>

          <Divider style={{ margin: "24px 0" }} />

          {/* Work Summary Section */}
          <div style={{ marginBottom: "32px" }}>
            <h3 style={{ fontSize: "14px", fontWeight: "700", color: "#0a0a0a", marginBottom: "16px", textTransform: "uppercase" }}>
              Work Summary
            </h3>
            <Row gutter={[16, 16]}>
              <Col span={12}>
                <DetailRow label="Working Days" value={payroll.workingDaysInMonth ?? "-"} />
              </Col>
              <Col span={12}>
                <DetailRow label="Present Days" value={payroll.presentDays ?? "-"} />
              </Col>
              <Col span={12}>
                <DetailRow label="Base Salary" value={n(payroll.baseSalarySnapshot)} />
              </Col>
              <Col span={12}>
                <DetailRow label="Regular Hours" value={payroll.regularHours != null ? `${payroll.regularHours}h` : "-"} />
              </Col>
            </Row>
          </div>

          <Divider style={{ margin: "24px 0" }} />

          {/* Compensation Section */}
          <div style={{ marginBottom: "32px" }}>
            <h3 style={{ fontSize: "14px", fontWeight: "700", color: "#0a0a0a", marginBottom: "16px", textTransform: "uppercase" }}>
              Compensation
            </h3>
            <Row gutter={[16, 16]}>
              <Col span={12}>
                <DetailRow label="Regular Pay" value={n(payroll.regularPay)} color="success" bold />
              </Col>
              <Col span={12}>
                <DetailRow label="Overtime Hours" value={payroll.otHours != null ? `${payroll.otHours}h` : "-"} color="warning" />
              </Col>
              <Col span={12}>
                <DetailRow label="Overtime Pay" value={n(payroll.otPay)} color="warning" />
              </Col>
            </Row>
          </div>

          <Divider style={{ margin: "24px 0", borderColor: "#52c41a", borderWidth: "2px" }} />

          {/* Net Salary */}
          <div style={{ marginBottom: "32px", padding: "16px", backgroundColor: "rgba(82, 196, 26, 0.05)", borderRadius: "8px" }}>
            <DetailRow label="NET SALARY" value={n(payroll.netSalary)} color="success" bold />
          </div>

          {/* Metadata */}
          <div style={{ marginTop: "32px", padding: "12px", backgroundColor: "#f5f7fa", borderRadius: "8px" }}>
            <DetailRow
              label="Generated At"
              value={payroll.generatedAt ? String(payroll.generatedAt).replace("T", " ").slice(0, 19) : "-"}
            />
          </div>
        </div>
      )}
    </Drawer>
  );
}
